('sprinter-w906', 'Mercedes-Benz', 'Sprinter', 'W906 (NCV3)', 2006, 2018, 'VW Crafter I (2006-2017 twin)', '{3250,3665,4325}', null, null, 'tbc', 'very-high', 'Huge used-camper population. Crafter I is the same vehicle. Track TBC.'),
('transporter-t5', 'Volkswagen', 'Transporter', 'T5', 2003, 2015, null, '{3000,3400}', null, null, 'tbc', 'very-high', 'Biggest UK used-camper base by volume. Track TBC (likely close to T6''s 1659/1628 - same PQ platform - but verify).'),
('transporter-t6', 'Volkswagen', 'Transporter', 'T6/T6.1', 2015, 2024, null, '{3000,3400}', 1659, 1628, 'med', 'very-high', 'Track from VW German technical data; some configs list rear 1659. Same wheelbases as T5.'),
('transit-custom-g1', 'Ford', 'Transit Custom', 'Gen 1', 2012, 2023, null, '{2933,3300}', null, null, 'tbc', 'high', 'Most used Customs are this gen. Track TBC.'),
('transit-custom-g2', 'Ford', 'Transit Custom', 'Gen 2', 2023, null, 'VW Transporter T7 (2024+ is a badge/platform twin)', '{3100,3500}', 1730, 1724, 'high', 'med', 'Track per carwow/Ford German spec. Note: the new VW Transporter T7 is built on this platform - NOT a T6 successor dimensionally.'),
('trafic-3', 'Renault', 'Trafic', 'III (X82)', 2014, null, 'Nissan NV300/Primastar / Vauxhall Vivaro B (2014-2019) / Fiat Talento (2016-2020)', '{3098,3498}', 1615, 1628, 'med', 'high', 'Vivaro B and Talento are badge twins of THIS - not of the 2019+ Stellantis Vivaro C.'),
