('transit-fullsize-g3', 'Ford', 'Transit', 'Gen 3 (V347/8)', 2000, 2014, null, '{2933,3300,3750}', null, null, 'tbc', 'med', 'Older self-builds. Wheelbase list and track TBC.'),
('master-x62', 'Renault', 'Master', 'III (X62)', 2010, 2024, 'Vauxhall Movano B (2010-2021) / Nissan NV400/Interstar', '{3182,3682,4332}', null, null, 'tbc', 'high', '14-year production run - most used Masters are this gen. Track TBC (~1750/1730 FWD, verify). NOTE: the v1 CSV''s ''new-gen Master'' rows actually used these X62 wheelbases.'),
