insert into chassis_types (chassis_id, chassis_type, fits_platforms, wheelbase_range_mm, front_track_mm, rear_track_mm_min, rear_track_mm_max, rear_track_confidence, axle_config, notes) values
('ducato-standard', 'Standard van chassis', 'Ducato/Boxer/Relay (Sevel 2006+)', '3000-4035', 1810, 1790, 1790, 'high', 'single', 'Unchanged from panel van (see van_dimensions_levelspot_v2.csv ducato-x250-x290-s8). Front track same across all Sevel chassis variants below - AL-KO/OEM motorhome conversions only ever touch the rear.'),
('ducato-oem-motorhome', 'Fiat factory ''Motorhome'' chassis-cab', 'Ducato (2006+, Fiat-branded only - not confirmed for Boxer/Relay badge)', 'varies-4-options', 1810, 1980, 1980, 'high', 'single', 'Fiat''s own lighter, lower-ground-clearance (145mm) chassis-cab for coachbuilders NOT using AL-KO. Source: Practical Motorhome ''Know your base vehicles''. Distinct from the AL-KO product below despite similar rear track figure - do not merge.'),
('alko-single-sevel', 'AL-KO single-axle low-frame', 'Ducato/Boxer/Relay, via AL-KO chassis technology (co-branded w/ Fiat/PSA)', 'varies', 1810, 1860, 1980, 'med', 'single', 'AL-KO''s own rear-track options are ~1860 and ~1980mm per their commercial-vehicle brochure (486/498 figures found were likely OCR''d from 186.0/198.0cm). Frame lowered vs standard chassis; independent torsion-bar rear suspension replaces the leaf-spring rigid axle. THE most common chassis under UK/EU coachbuilt low-profile and A-class motorhomes - e.g. every Swift Bolero used this, all AL-KO-chassis models generally.'),
('alko-single-sprinter', 'AL-KO single-axle low-frame', 'Mercedes Sprinter (907/906)', 'varies', 2020, 2170, 2230, 'low', 'single', 'Source states rear track ''increased by up to 210mm'' vs standard Sprinter (2020mm front / ~2020mm rear stock) - exact figure not confirmed, treat range as indicative only pending a real AL-KO Sprinter spec sheet.'),
('alko-tandem', 'AL-KO tandem (twin) rear axle', 'Ducato-based (confirmed: Hymer B694/B774); also used by other large A-class/tag-axle motorhomes across brands', '3800+', 1810, 1980, null, 'low', 'tandem', 'Twin rear axle for the longest/heaviest coachbuilts (>7.5m typical). Geometry model needs a THIRD axle plane for these - the app''s four-point/three-point models don''t cover tandem-rear vehicles; flag as a known gap, not a v1 target given ''international/exotic vehicle data'' is already out of scope.')
